def _debug_pi0_concat_inputs(label, tensor_list, dim):
    """Log ttnn.concat inputs for Pi0 embed_suffix / tt-xla #4633 isolation."""
    import sys

    lines = [f"[pi0 concat debug] {label} dim={dim} num_inputs={len(tensor_list)}"]
    for i, t in enumerate(tensor_list):
        try:
            shp = tuple(int(s) for s in t.shape)
        except (TypeError, ValueError):
            shp = tuple(t.shape)
        lines.append(
            f"  tensor[{i}] shape={shp} rank={len(shp)} dtype={t.dtype} "
            f"layout={t.layout} device={t.device()}"
        )
    print("\n".join(lines), file=sys.stderr, flush=True)


